import { truncate } from './text.ts';

/**
 * 統一的 ToolCall 介面
 * 各 agent 負責把自己的格式轉換成這個介面
 */
export interface ToolCall {
  name: string;
  input?: Record<string, unknown>;
}

export interface FormatToolOptions {
  /** 是否啟用 verbose 模式（不截斷） */
  verbose?: boolean;
}

/**
 * Subagent spawn tool 名稱（Claude Code renamed Task → Agent）
 */
export const SUBAGENT_TOOL_NAMES: ReadonlySet<string> = new Set([
  'Task',
  'Agent',
]);

/**
 * 判斷 tool 是否為 subagent spawn tool
 */
export function isSubagentTool(name: string): boolean {
  return SUBAGENT_TOOL_NAMES.has(name);
}

/**
 * Tool 類別（用於顏色區分）
 */
export type ToolCategory =
  | 'shell'
  | 'file'
  | 'search'
  | 'web'
  | 'task'
  | 'other';

/**
 * 根據 tool 名稱取得類別
 */
export function getToolCategory(toolName: string): ToolCategory {
  switch (toolName.toLowerCase()) {
    case 'bash':
    case 'shell':
    case 'shell_command':
    case 'run_shell_command':
      return 'shell';
    case 'read':
    case 'edit':
    case 'write':
    case 'read_file':
    case 'edit_file':
    case 'write_file':
      return 'file';
    case 'grep':
    case 'glob':
      return 'search';
    case 'webfetch':
    case 'websearch':
      return 'web';
    case 'task':
    case 'agent':
      return 'task';
    default:
      return 'other';
  }
}

/**
 * 格式化 tool_use，顯示關鍵參數摘要
 */
export function formatToolUse(
  name: string,
  input?: Record<string, unknown>,
  options: FormatToolOptions = {}

