find ~/.cursor/projects -name "*.jsonl" -size +1k 2>/dev/null | head -20 | while read f; do
  cat "$f"
done | python3 -c "
import json, sys
from collections import defaultdict
tools = defaultdict(set)
samples = {}
for line in sys.stdin:
    try:
        data = json.loads(line)
    except Exception:
        continue
    content = data.get('message', {}).get('content', [])
    if not isinstance(content, list):
        continue
    for part in content:
        if not isinstance(part, dict):
            continue
        if part.get('type') == 'tool_use':
            name = part.get('name', '?')
            input_keys = tuple(sorted((part.get('input') or {}).keys()))
            tools[name].add(input_keys)
            if name not in samples:
                samples[name] = part.get('input', {})

for name in sorted(tools.keys()):
    print(f'{name}:')
    for keys in tools[name]:
        print(f'  keys={list(keys)}')
    s = samples[name]
    short = {k: (str(v)[:60] + '...' if len(str(v)) > 60 else v) for k,v in s.items()}
    print(f'  sample={short}')
"

